@app.route("/admin/tokens", methods=["POST"])
def create_token():
    payload = request.get_json(silent=True) or {}
    token = payload.get("token")
    subject = payload.get("subject")
    scope = payload.get("scope", "")
    active = 1 if payload.get("active", True) else 0

    if not token:
        return jsonify({"error": "token is required"}), 400

    db = get_db()
    try:
        db.execute(
            "INSERT INTO access_tokens (token, active, subject, scope) VALUES (?, ?, ?, ?)",
            (token, active, subject, scope),
        )
        db.commit()
    except sqlite3.IntegrityError:
        return jsonify({"error": "token already exists"}), 409

    return jsonify({
        "token": token,
        "subject": subject,
        "scope": scope,
        "active": bool(active),
    }), 201


@app.route("/admin/tokens/<token>", methods=["DELETE"])
def revoke_token(token):
    db = get_db()
    result = db.execute(
        "UPDATE access_tokens SET active = 0 WHERE token = ?",
        (token,),
    )
    db.commit()

    if result.rowcount == 0:
        return jsonify({"error": "token not found"}), 404

    return jsonify({"revoked": True, "token": token}), 200


